// 1. Sadə interface
interface User {
  name: string;
  age: number;
}
const user: User = {
  name: "Murad",
  age: 25
};
console.log(user); // Çıxış: { name: "Murad", age: 25 }
// const invalidUser: User = { name: "Alice" }; // Xəta: age xüsusiyyəti əskikdir

// 2. Optional xüsusiyyətlər
interface Product {
  id: string;
  name: string;
  price?: number; // Optional xüsusiyyət
}
const book: Product = { id: "B001", name: "TypeScript Guide" };
console.log(book); // Çıxış: { id: "B001", name: "TypeScript Guide" }

// 3. Readonly xüsusiyyətlər
interface Car {
  readonly brand: string;
  model: string;
}
const car: Car = { brand: "Toyota", model: "Camry" };
console.log(car); // Çıxış: { brand: "Toyota", model: "Camry" }
// car.brand = "Honda"; // Xəta: readonly xüsusiyyət dəyişdirilə bilməz

// 4. Funksiya interfaceləri
interface Greet {
  (name: string, greeting?: string): string;
}
const sayHello: Greet = (name, greeting = "Hello") => `${greeting}, ${name}!`;
console.log(sayHello("Murad")); // Çıxış: Hello, Murad!
console.log(sayHello("Alice", "Hi")); // Çıxış: Hi, Alice!

// 5. Extends ilə miras alma
interface Person {
  name: string;
  age: number;
}
interface Employee extends Person {
  role: string;
}
const employee: Employee = {
  name: "Murad",
  age: 25,
  role: "Developer"
};
console.log(employee); // Çıxış: { name: "Murad", age: 25, role: "Developer" }

// 6. Union tipləri ilə interface
interface Book {
  type: "book";
  title: string;
  pages: number;
}
interface Movie {
  type: "movie";
  title: string;
  duration: number;
}
type Media = Book | Movie;
function describeMedia(media: Media): string {
  if (media.type === "book") {
    return `${media.title}: ${media.pages} pages`;
  }
  return `${media.title}: ${media.duration} minutes`;
}
const book: Book = { type: "book", title: "TypeScript Guide", pages: 200 };
const movie: Movie = { type: "movie", title: "Inception", duration: 148 };
console.log(describeMedia(book)); // Çıxış: TypeScript Guide: 200 pages
console.log(describeMedia(movie)); // Çıxış: Inception: 148 minutes

// Sadə mağaza sistemi
interface Product {
  id: string;
  name: string;
  price: number;
  inStock?: boolean;
}

function displayProduct(product: Product): string {
  return `${product.name} (ID: ${product.id}): $${product.price}, ${product.inStock ? "mövcuddur" : "mövcud deyil"}`;
}

const laptop: Product = {
  id: "P001",
  name: "Laptop",
  price: 1200,
  inStock: true
};
console.log(displayProduct(laptop)); // Çıxış: Laptop (ID: P001): $1200, mövcuddur

// Miras alma ilə
interface StockProduct extends Product {
  stockCount: number;
}
const stockLaptop: StockProduct = {
  id: "P001",
  name: "Laptop",
  price: 1200,
  inStock: true,
  stockCount: 10
};
console.log(`${stockLaptop.name}: ${stockLaptop.stockCount} ədəd`); // Çıxış: Laptop: 10 ədəd

